onOptionChange:
{{
  (async () => {
    await BookingForm_OLD_hastaFCL.setField(
      "incoterm_id",
      sl_incoterm.selectedOptionValue
    );

    await BookingForm_OLD_hastaFCL.clearChildren([
      "ciudad_incoterm_id",
      "ubicacion_internacional_id"
    ]);

    await q_ciudad_incoterm_dropdown.run();
  })()
}}

placeholderText:
{{
  !appsmith.store.booking_form?.pais_origen_id ||
  !appsmith.store.booking_form?.pol_id ||
  !appsmith.store.booking_form?.terminal_pol_id ||
  !appsmith.store.booking_form?.pais_destino_id ||
  !appsmith.store.booking_form?.pod_id
    ? "Complete origen, terminal y destino antes de seleccionar INCOTERM"
    : "Seleccione INCOTERM"
}}

sourceData:
{{
  (q_incoterms.data || []).filter(i => {
    const transporte = (sl_transporte.selectedOptionLabel || "").toUpperCase();
    const inc = (i.label || "").toUpperCase();

    const soloMaritimos = ["FAS", "FOB", "CFR", "CIF"];

    if (!transporte) return true;

    if (transporte.includes("MAR")) {
      return true;
    }

    return !soloMaritimos.includes(inc);
  })
}}
